mapper.sql:
SELECT venue_type as venueType, '' as venueTypeText, currency_code as currencyCode, user_id as userId, IFNULL(act_rebate_amount,0) as issueAmount, 0 as rebateAmount, 0 as status from user_rebate_venue_record where 1=1
AND site_code = #{vo.siteCode}
AND currency_code = #{vo.currencyCode}
AND `day_millis` >= #{vo.startTime}
AND `day_millis` <= #{vo.endTime}
union all SELECT venue_type as venueType, '' as venueTypeText, currency_code as currencyCode, user_id as userId, 0 as issueAmount, IFNULL(act_rebate_amount,0) as rebateAmount, 2 as status from user_rebate_venue_record where 1=1 and status = 2
AND site_code = #{vo.siteCode}
AND currency_code = #{vo.currencyCode}
AND `day_millis` >= #{vo.startTime}
AND `day_millis` <= #{vo.endTime}
union all SELECT '-1' as venueType, '人工加减额' as venueTypeText, currency_code as currencyCode, user_id as userId, case adjust_way when 1 then IFNULL(adjust_amount,0) else (0-IFNULL(adjust_amount,0)) end as issueAmount, 0 AS rebateAmount, 0 as status FROM user_manual_up_down_record where 1=1
AND site_code = #{vo.siteCode}
AND currency_code = #{vo.currencyCode}
AND `audit_datetime` >= #{vo.startTime}
AND `audit_datetime` <= #{vo.endTime}
and adjust_type=10 and audit_status = 3 union all SELECT '-1' as venueType, '人工加减额' as venueTypeText, currency_code as currencyCode, user_id as userId, 0 as issueAmount, case adjust_way when 1 then IFNULL(adjust_amount,0) else (0-IFNULL(adjust_amount,0)) end AS rebateAmount, 2 as status FROM user_manual_up_down_record where 1=1
AND site_code = #{vo.siteCode}
AND currency_code = #{vo.currencyCode}
AND `audit_datetime` >= #{vo.startTime}
AND `audit_datetime` <= #{vo.endTime}
and adjust_type=10 and audit_status = 3 and balance_change_status =1

mapper.select:
SELECT venue_type AS venueType, currency_code AS currencyCode, COUNT(DISTINCT user_id) AS receiveNums, IFNULL(sum(rebate_amount),0) AS rebateAmount FROM user_rebate_venue_record WHERE status = 2
AND site_code = #{vo.siteCode}
AND receive_time >= #{vo.startTime}
AND receive_time <= #{vo.endTime}
GROUP BY venueType, currencyCode ORDER BY venueType ASC, currencyCode ASC

SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(audit_datetime/1000),@@session.time_zone,#{vo.timeZoneDb}),'%Y-%m-%d') as issueTime, currency_code as currencyCode, COUNT(DISTINCT user_id) AS issueNums, case adjust_way when 1 then SUM(IFNULL(adjust_amount,0)) else sum((0-IFNULL(adjust_amount,0))) end AS issueAmount, COUNT(DISTINCT user_id) AS receiveNums, case adjust_way when 1 then SUM(IFNULL(adjust_amount,0)) else sum((0-IFNULL(adjust_amount,0))) end AS rebateAmount FROM user_manual_up_down_record where 1=1
AND site_code = #{vo.siteCode}
AND `currency_code` = #{vo.currencyCode}
AND `audit_datetime` >= #{vo.startTime}
AND `audit_datetime` <= #{vo.endTime}
and adjust_type=10 and audit_status = 3 and balance_change_status =1 GROUP BY audit_datetime,currencyCode,adjust_way ORDER BY audit_datetime DESC

SELECT DATE_FORMAT(CONVERT_TZ(FROM_UNIXTIME(day_millis/1000), @@session.time_zone,#{vo.timeZoneDb}),'%Y-%m-%d') as issueTime, currency_code as currencyCode, count(DISTINCT(user_id)) as issueNums, IFNULL(sum(act_rebate_amount),0) as issueAmount, COUNT(DISTINCT CASE WHEN status = 2 THEN user_id END) AS receiveNums, SUM(CASE WHEN status = 2 THEN act_rebate_amount END) AS rebateAmount from user_rebate_venue_record where 1=1
AND site_code = #{vo.siteCode}
AND `currency_code` = #{vo.currencyCode}
AND `venue_type` = #{vo.venueType}
AND `day_millis` >= #{vo.startTime}
AND `day_millis` <= #{vo.endTime}
GROUP BY day_millis, currencyCode ORDER BY day_millis ASC, currencyCode ASC
